css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #0a0a0a; color: white; overflow-x: hidden; }
.navbar { display: flex; justify-content: space-between; align-items: center; padding: 24px 60px; }
.brand { font-size: 19px; font-weight: 800; letter-spacing: 0.05em; }
.nav-links { display: flex; gap: 28px; }
.nav-links a { color: rgba(255,255,255,0.5); text-decoration: none; font-size: 14px; font-weight: 600; }
.nav-links a.active { color: #facc15; }
.hero { display: flex; align-items: center; gap: 50px; padding: 50px 60px 90px; flex-wrap: wrap; }
.hero-text { flex: 1; min-width: 320px; }
.badge { display: inline-block; color: #facc15; font-size: 12px; font-weight: 800; letter-spacing: 0.18em; margin-bottom: 22px; }
.hero-text h1 { font-size: 48px; font-weight: 800; line-height: 1.25; margin-bottom: 18px; }
.hero-text h1 span { color: #facc15; }
.hero-text p { color: rgba(255,255,255,0.5); font-size: 15px; line-height: 1.8; margin-bottom: 28px; max-width: 480px; }
.btn-primary { background: linear-gradient(135deg, #facc15, #f59e0b); border: none; color: #1a1a1a; padding: 15px 30px; border-radius: 999px; font-size: 14px; font-weight: 800; cursor: pointer; }
.hero-reel { flex: 1; min-width: 280px; aspect-ratio: 16/10; background: linear-gradient(150deg, #1f1f1f, #050505); border-radius: 18px; display: flex; align-items: center; justify-content: center; cursor: pointer; position: relative; }
.play-overlay { width: 70px; height: 70px; border-radius: 50%; background: rgba(255,255,255,0.1); border: 2px solid rgba(255,255,255,0.25); display: flex; align-items: center; justify-content: center; font-size: 22px; backdrop-filter: blur(6px); }
.work { padding: 0 60px 70px; }
.work h2 { font-size: 30px; font-weight: 800; margin-bottom: 26px; }
.filter-row { display: flex; gap: 10px; margin-bottom: 26px; flex-wrap: wrap; }
.filter { background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.1); color: rgba(255,255,255,0.55); padding: 9px 18px; border-radius: 999px; font-size: 13px; font-weight: 700; cursor: pointer; }
.filter.active { background: rgba(250,204,21,0.15); color: #facc15; border-color: rgba(250,204,21,0.3); }
.video-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(220px, 1fr)); gap: 20px; }
.video-card { cursor: pointer; }
.video-thumb { aspect-ratio: 16/9; background: linear-gradient(150deg, #1f1f1f, #050505); border-radius: 12px; display: flex; align-items: center; justify-content: center; position: relative; margin-bottom: 12px; transition: 0.2s; }
.video-card:hover .video-thumb { filter: brightness(1.15); }
.video-thumb .play-overlay { width: 46px; height: 46px; font-size: 14px; }
.video-card h3 { font-size: 15px; font-weight: 700; margin-bottom: 4px; }
.video-card span { font-size: 12px; color: rgba(255,255,255,0.4); font-weight: 600; text-transform: uppercase; letter-spacing: 0.05em; }
.services { padding: 70px 60px; background: rgba(255,255,255,0.02); }
.services h2 { font-size: 30px; font-weight: 800; text-align: center; margin-bottom: 36px; }
.service-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 24px; max-width: 1000px; margin: 0 auto; }
.service { text-align: center; }
.sicon { font-size: 32px; margin-bottom: 12px; }
.service h3 { font-size: 16px; font-weight: 700; margin-bottom: 8px; }
.service p { color: rgba(255,255,255,0.45); font-size: 13px; line-height: 1.6; }
.contact { text-align: center; padding: 80px 60px; }
.contact h2 { font-size: 30px; font-weight: 800; margin-bottom: 10px; }
.contact p { color: rgba(255,255,255,0.5); font-size: 14px; margin-bottom: 26px; }
.contact button { background: rgba(255,255,255,0.06); border: 1px solid rgba(255,255,255,0.15); color: white; padding: 15px 32px; border-radius: 999px; font-size: 14px; font-weight: 700; cursor: pointer; }
.modal { position: fixed; inset: 0; background: rgba(0,0,0,0.85); display: none; align-items: center; justify-content: center; padding: 20px; z-index: 10; }
.modal.show { display: flex; }
.modal-content { background: #141414; border-radius: 16px; padding: 28px; max-width: 460px; width: 100%; text-align: center; }
.modal-video { aspect-ratio: 16/9; background: linear-gradient(150deg, #1f1f1f, #050505); border-radius: 12px; display: flex; align-items: center; justify-content: center; margin-bottom: 18px; }
.modal-video .play-overlay { width: 60px; height: 60px; font-size: 18px; }
.modal-content h2 { font-size: 20px; font-weight: 800; margin-bottom: 6px; }
.modal-content span { display: block; color: rgba(255,255,255,0.4); font-size: 12.5px; font-weight: 600; text-transform: uppercase; letter-spacing: 0.05em; margin-bottom: 20px; }
.close-btn { background: rgba(250,204,21,0.15); color: #facc15; border: none; padding: 12px 28px; border-radius: 999px; font-size: 14px; font-weight: 700; cursor: pointer; }
@media (max-width: 900px) { .navbar, .hero, .work, .services, .contact { padding-left: 24px; padding-right: 24px; } .nav-links { display: none; } .hero-text h1 { font-size: 30px; } }

js:
const videos = [
  { title: 'Aurora Marka Filmi', cat: 'brand', label: 'Marka Filmi' },
  { title: 'Ada & Mert Düğünü', cat: 'wedding', label: 'Düğün' },
  { title: 'Gece Yolu - Müzik Videosu', cat: 'music', label: 'Müzik Videosu' },
  { title: 'Lansman Filmi - Nova', cat: 'brand', label: 'Marka Filmi' },
  { title: 'Selin & Kaan Düğünü', cat: 'wedding', label: 'Düğün' },
  { title: 'Şehir Işıkları - Klip', cat: 'music', label: 'Müzik Videosu' }
];

function renderVideos(filter) {
  const grid = document.getElementById('videoGrid');
  grid.innerHTML = '';
  videos
    .filter(v => filter === 'all' || v.cat === filter)
    .forEach(v => {
      const card = document.createElement('div');
      card.className = 'video-card';
      card.innerHTML = `<div class="video-thumb"><span class="play-overlay">▶</span></div><h3>${v.title}</h3><span>${v.label}</span>`;
      card.addEventListener('click', () => openModal(v));
      grid.appendChild(card);
    });
}

function filterVideos(btn, filter) {
  document.querySelectorAll('.filter').forEach(f => f.classList.remove('active'));
  btn.classList.add('active');
  renderVideos(filter);
}

function openModal(v) {
  document.getElementById('modalTitle').textContent = v.title;
  document.getElementById('modalCat').textContent = v.label;
  document.getElementById('modal').classList.add('show');
}

function closeModal(e) {
  if (e.target.id === 'modal' || e.target.classList.contains('close-btn')) {
    document.getElementById('modal').classList.remove('show');
  }
}

function playReel() {
  alert('Showreel oynatılıyor...');
}

document.getElementById('heroReel').addEventListener('click', playReel);

function contactMe() {
